#include<cstdio>
#include<cstring>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
typedef unsigned long long uLL;
inline uLL read()
{
	uLL res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline void print(const uLL &x){if(x>9u)print(x/10u);putchar(x%10u+'0');}
const int N=5e7+10,W=N-10;int pm[N>>4],cpt;uLL ph[N];bool vs[N];//uLL sph[2400];
inline void Init()
{
	ph[1]=1;rep(2,W,i)
	{
		if(!vs[i])ph[pm[++cpt]=i]=i-1;
		for(int j=1;j<=cpt&&pm[j]*i<=W;++j)
		{
			vs[pm[j]*i]=true;
			if(i%pm[j]==0){ph[i*pm[j]]=ph[i]*pm[j];break;}
			ph[i*pm[j]]=ph[i]*(pm[j]-1);
		}
		ph[i]+=ph[i-1];
	}
}
inline uLL Sum(uLL x){return x&1?((x+1)>>1)*(x):(x>>1)*(x+1);}
#include<unordered_map>
std::unordered_map<uLL,uLL> sph;
inline uLL Phi(uLL n)
{
	if(n<=W)return ph[n];if(sph.count(n))return sph[n]; uLL &res=sph[n]=Sum(n);
	for(uLL l=2,r=0;l<=n;l=r+1){r=n/(n/l);res-=(r-l+1)*Phi(n/l);} return res;
}
inline uLL Sum_Phi(uLL n){return Phi(n);}
inline void Solve()
{
	uLL n=read(),ans=0;
	for(uLL l=1,r=0;l<=n;l=r+1){r=n/(n/l);ans+=(Sum_Phi(n/l)-1)*(Sum(r)-Sum(l-1));}
	print(ans);putchar('\n');return;
}
int main(){Init();uLL T=read();while(T--)Solve();}
